import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface GangMemberData {
    userId: number;
    username: string;
    rankId: number;
    rankName: string;
    figure: string;
}

export class GangMembersParser implements IMessageParser {
    private _members: GangMemberData[] = [];

    public flush(): boolean {
        this._members = [];
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        const count = wrapper.readInt();

        for (let i = 0; i < count; i++) {
            this._members.push({
                userId: wrapper.readInt(),
                username: wrapper.readString(),
                rankId: wrapper.readInt(),
                rankName: wrapper.readString(),
                figure: wrapper.readString(),
            });
        }

        return true;
    }

    public get members(): GangMemberData[] {
        return this._members;
    }
}
